import{kn as e}from"./chunk-DCq2tb4F.js";var t=e(),n={publishing_date:`2025-01-06`,title:`Moving old lectures`,category:`quantum`,secondaryCategory:`webdev`,description:`I migrate academic lectures from LaTeX to modern web formats. Discover solutions for handling equations, references, and static site generation in JavaScript environments.`};function r(e){let n={a:`a`,code:`code`,h2:`h2`,li:`li`,p:`p`,ul:`ul`,...e.components};return(0,t.jsxs)(t.Fragment,{children:[(0,t.jsx)(n.p,{children:`In my time in academia, I gave a few lectures on various topics. They are saved as latex, markdown, jupyter notebook, whatever you want. But to get started, I decided to move over a number of lectures on AMO that I gave for several years.`}),`
`,(0,t.jsx)(n.p,{children:`I had them all saved on a website called Authorea and could export them directly as latex. So what could be easier than just importing them right ?`}),`
`,(0,t.jsx)(n.h2,{children:`Challenge 1: Loading the markdown`}),`
`,(0,t.jsxs)(n.p,{children:[`It was really quite straight forward to convert the files through pandoc with the command `,(0,t.jsx)(n.code,{children:`pandoc MY__INPUT_FILE.tex -s -o MY_FILE.md`}),`. However, once you have markdown I have to import it into the website. And it is really at this stage where my little python world crumbles. You have the habit that files are yours and any access from any script is identical. However, within the world of javascript, I suddenly had to think about strange things like clients / servers / build times etc. In the end, I chose a solution similiar to the one described by `,(0,t.jsx)(n.a,{href:`https://vike.dev/markdown`,children:`vike`}),` with a little script that converts the markdown into a json file. This json file is then loaded into the website without the need of any `,(0,t.jsx)(n.code,{children:`fs`}),`.`]}),`
`,(0,t.jsx)(n.h2,{children:`Challenge 2: Equations and references`}),`
`,(0,t.jsx)(n.p,{children:`The first challenge, already existed for the blogs in general. But now I also had to handle equations and references. To render them you need a surprising amount of extensions to remark including:`}),`
`,(0,t.jsxs)(n.ul,{children:[`
`,(0,t.jsxs)(n.li,{children:[(0,t.jsx)(n.a,{href:`https://www.npmjs.com/package/rehype-katex`,children:`rehype-katex`}),` for compiling the equations.`]}),`
`,(0,t.jsxs)(n.li,{children:[(0,t.jsx)(n.a,{href:`https://github.com/remarkjs/remark-gfm`,children:`remark-gfm`}),` for references in footnotes`]}),`
`,(0,t.jsxs)(n.li,{children:[(0,t.jsx)(n.a,{href:`https://www.npmjs.com/package/remark-math`,children:`remark-math`}),` for compiling equations.`]}),`
`]}),`
`,(0,t.jsx)(n.p,{children:`Despite all of those packages I needed to write a processing script that removed equation labels, equation alignements and also keep the spacing right. All in all it is nicer to use latex for long documents ...`}),`
`,(0,t.jsx)(n.h2,{children:`Challenge 3: Images`}),`
`,(0,t.jsxs)(n.p,{children:[`Now I was already quite proud about the result, but then I realized that the images were not loading. Remember how I was loading markdown into a `,(0,t.jsx)(n.code,{children:`json`}),` ? Well this messed up the references to images in production. So I had to copy the images into public folder. Further, I had to find a way to keep the images at an appropiate size. This worked nicely with the `,(0,t.jsx)(n.code,{children:`img`}),` link, but to have this you must allow for `,(0,t.jsx)(n.a,{href:`https://www.npmjs.com/package/rehype-raw`,children:`rehype-raw`}),`. But then it was all good.`]}),`
`,(0,t.jsx)(n.h2,{children:`Conclusion`}),`
`,(0,t.jsxs)(n.p,{children:[`Building up this kind of content management is really only for the curious. Otherwise, projects like docusaurus or astro are much more suited. But now I have a cute little system puzzled together and can extend it at will. All of this with a very limited amount of complexity. FWIW, the code can be `,(0,t.jsx)(n.a,{href:`https://github.com/fretchen/fretchen.github.io`,children:`found here`}),`.`]})]})}function i(e={}){let{wrapper:n}=e.components||{};return n?(0,t.jsx)(n,{...e,children:(0,t.jsx)(r,{...e})}):r(e)}export{i as default,n as frontmatter};